import requests

BASE_URL = "http://127.0.0.1:5001"
HEADERS = {
    "x-user-id": "ecfa9793-3dcd-4dbb-b666-49acfa7d7ec9",
    "Content-Type": "application/json"
}
TIMEOUT = 30

def test_post_api_chat_tutor_with_insufficient_credits():
    bite_payload = {"topic": "Biology"}
    question_context = None

    try:
        resp_bite = requests.post(
            f"{BASE_URL}/api/generate-bite",
            json=bite_payload,
            headers=HEADERS,
            timeout=TIMEOUT
        )
        resp_bite.raise_for_status()
        bite_data = resp_bite.json()
        if "question" in bite_data:
            question_context = bite_data["question"]
        elif "questionId" in bite_data:
            question_context = {"questionId": bite_data["questionId"]}
        else:
            question_context = bite_data
    except Exception:
        question_context = {"dummy": True}

    chat_payload = {
        "message": "문의가 있습니다.",
        "question_context": question_context,
        "persona": "친절한 과외쌤"
    }

    resp_chat = None
    try:
        resp_chat = requests.post(
            f"{BASE_URL}/api/chat-tutor",
            json=chat_payload,
            headers=HEADERS,
            timeout=TIMEOUT
        )
    except requests.RequestException as e:
        err_str = str(e).lower()
        assert ("credit" in err_str or "403" in err_str or "400" in err_str), "Expected credit related error or client error status"
        assert False, f"RequestException occurred: {e}"

    assert resp_chat is not None, "No response received from /api/chat-tutor"

    if resp_chat.status_code == 200:
        try:
            json_resp = resp_chat.json()
        except ValueError:
            assert False, "Response is not valid JSON"

        msg = json_resp.get("message", "") or json_resp.get("error", "")
        assert ("충전 필요" in msg or "charge" in msg.lower() or "insufficient" in msg.lower()), f"Expected insufficent credit message, got: {msg}"
    else:
        assert resp_chat.status_code in (400, 402, 403), f"Expected 4xx error due to insufficient credits, got: {resp_chat.status_code}"

test_post_api_chat_tutor_with_insufficient_credits()

import requests

BASE_URL = "http://127.0.0.1:5001"
HEADERS = {
    "x-user-id": "ecfa9793-3dcd-4dbb-b666-49acfa7d7ec9",
    "Content-Type": "application/json"
}

def test_post_api_get_summary_with_recent_mistakes():
    url = f"{BASE_URL}/api/get-summary"
    payload = {
        "userId": "ecfa9793-3dcd-4dbb-b666-49acfa7d7ec9"
    }

    try:
        response = requests.post(url, json=payload, headers=HEADERS, timeout=30)
        response.raise_for_status()

        data = response.json()

        # Validate response is a JSON object with some content
        assert isinstance(data, dict), "Response is not a JSON object"
        assert len(data) > 0, "Response JSON object is empty"

        # Relaxed check: verify presence of keys or lists indicating summary
        keys_of_interest = ["recentMistakes", "wrongAnswers", "weakTopics", "items", "summary", "message"]
        assert any(key in data for key in keys_of_interest), "Response missing summary or mistake indication keys"

        # Check for retry options or wrong answers presence, or allow valid empty message
        retry_found = False
        if "items" in data and isinstance(data["items"], list) and len(data["items"]) > 0:
            for item in data["items"]:
                if isinstance(item, dict) and ("retry" in item or "questionId" in item):
                    retry_found = True
                    break
        elif "wrongAnswers" in data and isinstance(data["wrongAnswers"], list) and len(data["wrongAnswers"]) > 0:
            retry_found = True
        elif "message" in data and isinstance(data["message"], str) and "최근 틀린 문제가 없습니다" in data["message"]:
            retry_found = True

        assert retry_found, "No retry options, wrong answer items, or valid empty message found in summary response"

    except requests.exceptions.RequestException as e:
        assert False, f"Request failed: {e}"


test_post_api_get_summary_with_recent_mistakes()

import requests

BASE_URL = "http://127.0.0.1:5001"
HEADERS = {
    "x-user-id": "ecfa9793-3dcd-4dbb-b666-49acfa7d7ec9",
    "Content-Type": "application/json"
}

def test_post_api_get_summary_no_recent_mistakes():
    url = f"{BASE_URL}/api/get-summary"
    payload = {
        "userId": "ecfa9793-3dcd-4dbb-b666-49acfa7d7ec9"
    }
    try:
        response = requests.post(url, json=payload, headers=HEADERS, timeout=30)
        response.raise_for_status()
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    json_data = response.json()
    assert isinstance(json_data, dict), "Response should be a JSON object"

    # Combine all string values to search expected messages
    def extract_strings(obj):
        if isinstance(obj, dict):
            for v in obj.values():
                yield from extract_strings(v)
        elif isinstance(obj, list):
            for item in obj:
                yield from extract_strings(item)
        elif isinstance(obj, str):
            yield obj

    all_strings = list(extract_strings(json_data))

    expected_message = "최근 틀린 문제가 없습니다. 더 많은 문제를 풀어보세요"
    expected_cta = "Daily Bite로 돌아가기"

    assert any(expected_message in s for s in all_strings), f"Expected message '{expected_message}' not found in response"
    assert any(expected_cta in s for s in all_strings), f"Expected CTA '{expected_cta}' not found in response"


test_post_api_get_summary_no_recent_mistakes()
